import React from "react";
import styles from "./quantity.module.css";

interface QuantityProps {
    count: number;
    setCount: React.Dispatch<React.SetStateAction<number>>;
}

const Quantity: React.FC<QuantityProps> = ({ setCount, count }) => {
  const handleDecrease = () => {
    if (count > 1) {
      setCount(count - 1);
    } else {
      setCount(1);
    }
  };

  const handleIncrease = () => {
    setCount(count + 1);
  };
  return (
    <div className={styles.wrapper_quantity}>
      <p className={styles.title_quantity}>Quantity</p>
      <button className={styles.btn_quanity} onClick={handleDecrease} />
      <span className={styles.count_quantity}>{count}x</span>
      <button className={styles.btn_quanity} onClick={handleIncrease} />
    </div>
  );
};

export default Quantity;
